#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        int *next = (int*)calloc(N+1, sizeof(int)); // 0 = null
        for (int i = 0; i < M; ++i) {
            int u, v; scanf("%d %d", &u, &v);
            next[u] = v;
        }
        int *vis = (int*)calloc(N+1, sizeof(int));
        int cur = 1;
        int circular = 0;
        while (cur != 0 && !vis[cur]) {
            vis[cur] = 1;
            cur = next[cur];
        }
        if (cur == 1) circular = 1; // returned to head
        printf(circular ? "YES\n" : "NO\n");
        free(next);
        free(vis);
    }
    return 0;
}

